7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- This entity implements a simple SPI-master.
11	
12	------------------------------------------------------------------------------
13	-- Libraries
14	------------------------------------------------------------------------------
15	library ieee;
16		use ieee.std_logic_1164.all;
17		use ieee.numeric_std.all;
18		use ieee.math_real.all;
19		
20	library work;
21		use work.psi_common_math_pkg.all;
22		use work.definitions_pkg.all;
23		
24	------------------------------------------------------------------------------
25	-- Entity Declaration
26	------------------------------------------------------------------------------
27	entity spi_simple is
28		generic (
29			ClockDivider_g	: natural range 4 to 1_000_000;		
30			TransWidth_g	: positive;							
31			CsHighCycles_g	: positive;							
32			SpiCPOL_g		: natural range 0 to 1;				
33			SpiCPHA_g		: natural range 0 to 1;				
34			SlaveCnt_g		: positive := 1;					
35			LsbFirst_g		: boolean := false;
36			FifoDepth_g		: positive	:= 256;
37			MosiIdleState_g : std_logic := '0';
38		  ReadBitPol_g     : std_logic := '1';        
39	    TriStatePol_g    : std_logic := '1'; 
40	    SpiDataPos_g     : positive := 3         
41		);
42		port (
43			-- Control Signals
44			Clk			: in	std_logic;	
45			Rst			: in	std_logic;	
46			
47	
48			-- Config Interface
49			CfgSlave		: in	std_logic_vector(log2ceil(SlaveCnt_g)-1 downto 0);
50			CfgStoreRx		: in	std_logic;
51			CfgTxAlmEmpty	: in 	std_logic_vector(log2ceil(FifoDepth_g) downto 0);
52			CfgRxAlmFull	: in	std_logic_vector(log2ceil(FifoDepth_g) downto 0);
53			
